Greedy minimum cost insertion: for each order, evaluate all valid insertions across existing routes, select the assignment yielding the lowest total route cost, and if none feasible, spawn a new vehicle.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		shipID := total_ship + jj
		ori := oris[jj]
		des := dess[jj]

		bestCost := -1.0
		bestIdx := -1

		// Evaluate insertion into every existing assign
		for i := 0; i < dispatch.AssignsLen; i++ {
			if !dispatch.Assigns[i].AddShip(shipID, ori, des) {
				continue
			}
			dispatch.Assigns[i].GenRoute()
			if dispatch.Assigns[i].Cost >= 0.0 {
				if bestIdx < 0 || dispatch.Assigns[i].Cost < bestCost {
					bestCost = dispatch.Assigns[i].Cost
					bestIdx = i
				}
			}
			// Revert to original state
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}

		if bestIdx >= 0 {
			// Apply the best insertion
			dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
		} else {
			// Fallback: try a brand new assign (seed)
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[newIdx].GenRoute()
				// Accept even if invalid to guarantee insertion
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

